      floorId: floor.id,
    }
  ));
}

function buildBeamObjects(floor) {
  return (floor.beams || [])
    .map((beam) => {
      const renderData = getBeamRenderData(beam, floor.columns || []);
      if (!renderData) return null;

      return createLinearBoxDescriptor(
        beam.id,
        'beam',
        renderData.start,
        renderData.end,
        beam.width,
        beam.floorLevel - beam.depth,
        beam.depth,
        {
          sourceId: beam.id,
          floorId: floor.id,
        }
      );
    })
    .filter(Boolean);
}

