 18→function uniqueSortedValues(values = []) {
 19→  const sorted = [...values].sort((a, b) => a - b);
 20→  return sorted.filter((value, index) => (
 21→    index === 0 || Math.abs(value - sorted[index - 1]) > 1e-4
 22→  ));
 23→}
 24→
 25→function intervalFromValues(values, maxLength) {
 26→  if (!values.length) return null;
 27→  const clamped = values
 28→    .map((value) => clamp(value, 0, maxLength))
 29→    .filter((value) => value >= -EPSILON && value <= maxLength + EPSILON);
 30→  if (!clamped.length) return null;
 31→
 32→  const left = Math.min(...clamped);
 33→  const right = Math.max(...clamped);
 34→  if (right - left < EPSILON) return null;
 35→  return { left, right };
