 45→  const values = [];
 46→  for (let index = 0; index < polygon.length; index += 1) {
 47→    const start = polygon[index];
 48→    const end = polygon[(index + 1) % polygon.length];
 49→    const hit = segmentIntersection(sectionCut.startPoint, sectionCut.endPoint, start, end);
 50→    if (hit) {
