 52→    }
 53→  }
 54→
 55→  if (pointInPolygon(sectionCut.startPoint, polygon)) values.push(0);
 56→  if (pointInPolygon(sectionCut.endPoint, polygon)) values.push(sectionCutLength(sectionCut));
