    .filter((value) => value >= -EPSILON && value <= maxLength + EPSILON);
  if (!clamped.length) return null;

  const left = Math.min(...clamped);
  const right = Math.max(...clamped);
  if (right - left < EPSILON) return null;
  return { left, right };
