function projectPolygon(sectionCut, polygon = []) {
  return polygon.map((point) => projectPointToSectionCut(sectionCut, point));
}

function polygonCutInterval(sectionCut, polygon = []) {
  if (polygon.length < 3) return null;

  const values = [];
