 1→import { buildFloorPreviewObjects } from './objectBuilders';
 2→import { getDefaultActiveFloorId, getFloorElevation, getFloorStackBounds, getOrderedFloors } from '@/domain/floorModels';
 3→
 4→function mergeBounds(current, next) {
 5→  if (!next) return current;
 6→  if (!current) return { ...next };
 7→
 8→  return {
 9→    minX: Math.min(current.minX, next.minX),
10→    maxX: Math.max(current.maxX, next.maxX),
11→    minY: Math.min(current.minY, next.minY),
12→    maxY: Math.max(current.maxY, next.maxY),
13→    minElevation: Math.min(current.minElevation, next.minElevation),
14→    maxElevation: Math.max(current.maxElevation, next.maxElevation),
15→  };
16→}
17→
18→function boundsFromObjects(objects = []) {
19→  return objects.reduce((accumulator, objectDescriptor) => (
20→    mergeBounds(accumulator, objectDescriptor.bounds)
21→  ), null);
22→}
23→
24→function createFallbackBounds(stackBounds, activeFloor) {
25→  const level = stackBounds?.minElevation ?? getFloorElevation(activeFloor);
26→  const top = stackBounds?.maxElevation ?? (level + 3000);
27→  return {
28→    minX: -1500,
29→    maxX: 1500,
30→    minY: -1500,
31→    maxY: 1500,
32→    minElevation: level,
33→    maxElevation: top,
34→  };
35→}
36→
37→export function buildPreviewScene(project, options = {}) {
38→  const floors = getOrderedFloors(project);
39→  const activeFloorId = getDefaultActiveFloorId(project, options.activeFloorId);
40→  const activeFloor = floors.find((floor) => floor.id === activeFloorId) || null;
41→  const stackBounds = getFloorStackBounds(floors);
42→  const resolvedVisibleFloorIds = options.visibleFloorIds || floors.map((floor) => floor.id);
43→  const visibleFloorIds = new Set(resolvedVisibleFloorIds);
44→
45→  const floorDescriptors = floors.map((floor) => {
46→    const objects = buildFloorPreviewObjects(floor);
47→    return {
48→      floorId: floor.id,
49→      name: floor.name,
50→      elevation: getFloorElevation(floor),
51→      visible: visibleFloorIds.has(floor.id),
52→      objects,
53→      bounds: boundsFromObjects(objects),
54→    };
55→  });
56→
57→  const visibleObjects = floorDescriptors
58→    .filter((floor) => floor.visible)
59→    .flatMap((floor) => floor.objects);
60→  const bounds = boundsFromObjects(visibleObjects) || createFallbackBounds(stackBounds, activeFloor);
61→
62→  return {
63→    activeFloorId,
64→    visibleFloorIds: [...visibleFloorIds],
65→    floors: floorDescriptors,
66→    bounds,
67→    defaultTarget: {
68→      x: (bounds.minX + bounds.maxX) / 2,
69→      y: (bounds.minElevation + bounds.maxElevation) / 2,
70→      z: (bounds.minY + bounds.maxY) / 2,
71→    },
72→    groundLevel: stackBounds.minElevation,
73→    hasVisibleObjects: visibleObjects.length > 0,
74→  };
75→}
