 16→
 17→function boundsFromPoints(points = [], fallback = { minX: -1000, maxX: 1000, minY: -1000, maxY: 1000 }) {
 18→  if (!points.length) return fallback;
 19→  return {
 20→    minX: Math.min(...points.map((point) => point.x)),
 21→    maxX: Math.max(...points.map((point) => point.x)),
 22→    minY: Math.min(...points.map((point) => point.y)),
 23→    maxY: Math.max(...points.map((point) => point.y)),
 24→  };
 25→}
 26→
 27→function expandBounds(bounds, paddingX, paddingY = paddingX) {
 28→  return {
 29→    minX: bounds.minX - paddingX,
 30→    maxX: bounds.maxX + paddingX,
 31→    minY: bounds.minY - paddingY,
 32→    maxY: bounds.maxY + paddingY,
 33→  };
 34→}
 35→
 36→function collectPlanPoints(floor) {
 37→  const points = [];
 38→
 39→  for (const wall of floor.walls || []) {
 40→    points.push(...(getWallRenderData(wall, floor.columns || []).outline || []));
 41→  }
 42→  for (const room of floor.rooms || []) {
 43→    points.push(...(room.points || []));
 44→  }
 45→  for (const beam of floor.beams || []) {
 46→    const renderData = getBeamRenderData(beam, floor.columns || []);
 47→    if (renderData?.outline) points.push(...renderData.outline);
 48→  }
 49→  for (const stair of floor.stairs || []) {
 50→    const renderData = getStairRenderData(stair);
 51→    if (renderData?.outline) points.push(...renderData.outline);
 52→  }
 53→  for (const column of floor.columns || []) {
 54→    points.push(...columnOutline(column));
 55→  }
 56→  for (const slab of (floor.slabs || [])) {
 57→    const rd = getSlabRenderData(slab);
 58→    if (rd?.boundaryPoints) points.push(...rd.boundaryPoints);
 59→  }
 60→  for (const sc of (floor.sectionCuts || [])) {
 61→    points.push(sc.startPoint, sc.endPoint);
 62→    const renderData = getSectionCutRenderData(sc);
 63→    if (renderData?.arrow) {
 64→      points.push(renderData.arrow.shaftStart, renderData.arrow.shaftEnd, renderData.arrow.headA, renderData.arrow.headB);
 65→    }
 66→  }
 67→
 68→  for (const door of floor.doors || []) {
 69→    const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
 70→    if (!wall) continue;
 71→    const outline = doorOutlineOnWall(wall, door);
 72→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 73→  }
 74→
 75→  for (const windowItem of floor.windows || []) {
 76→    const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
 77→    if (!wall) continue;
 78→    const outline = windowOutlineOnWall(wall, windowItem);
 79→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 80→  }
 81→
 82→  return points;
 83→}
