 85→function buildPlanSource(floor) {
 86→  if (!floor) {
 87→    return {
 88→      kind: 'empty',
 89→      title: 'Plan',
 90→      message: 'Missing floor.',
 91→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
