 95→  const geometryBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);
 96→
 97→  return {
 98→    kind: 'plan',
 99→    title: `${floor.name} Plan`,
100→    floor,
101→    bounds: geometryBounds,
102→  };
103→}
