163→export function resolveSheetViewportSource(project, viewport) {
164→  const defaultFloorId = getDefaultActiveFloorId(project, viewport.sourceFloorId);
165→  const floor = resolveProjectFloor(project, defaultFloorId);
166→
167→  switch (viewport.sourceView) {
168→    case 'section':
169→      return buildSectionSource(project, floor, viewport.sourceRefId);
170→    case 'elevation_front':
171→    case 'elevation_rear':
172→    case 'elevation_left':
173→    case 'elevation_right':
174→      return buildElevationSource(project, floor, viewport.sourceView);
175→    case 'plan':
176→    default:
177→      return buildPlanSource(floor);
178→  }
179→}
