 17→function buildTitleBlock(project, sheet, paper) {
 18→  const titleBlockWidth = Math.min(130, paper.width * 0.42);
 19→  const x = paper.width - SHEET_MARGIN - titleBlockWidth;
 20→  const y = paper.height - SHEET_MARGIN - TITLE_BLOCK_HEIGHT;
 21→
