 39→function buildViewportFrame(viewport, source) {
 40→  const bounds = source.bounds || { minX: 0, maxX: 1000, minY: 0, maxY: 1000 };
 41→  const scale = 1 / resolveViewportScale(viewport);
 42→  const sourceWidth = Math.max(1, bounds.maxX - bounds.minX);
 43→  const sourceHeight = Math.max(1, bounds.maxY - bounds.minY);
 44→  const innerWidth = Math.max(10, viewport.width - CONTENT_PADDING * 2);
 45→  const innerHeight = Math.max(10, viewport.height - CONTENT_PADDING * 2);
 46→  const drawnWidth = sourceWidth * scale;
 47→  const drawnHeight = sourceHeight * scale;
 48→
 49→  const translateX = Math.max(0, (innerWidth - drawnWidth) / 2) - bounds.minX * scale;
 50→  const translateY = Math.max(0, (innerHeight - drawnHeight) / 2) - bounds.minY * scale;
 51→
 52→  return {
 53→    ...viewport,
 54→    rotation: viewport.rotation || 0,
 55→    title: resolveViewportTitle(viewport, source),
 56→    source,
 57→    clipRect: {
 58→      x: viewport.x + CONTENT_PADDING,
 59→      y: viewport.y + CONTENT_PADDING,
 60→      width: innerWidth,
 61→      height: innerHeight,
 62→    },
 63→    contentTransform: {
 64→      translateX,
 65→      translateY,
 66→      scale,
 67→    },
 68→  };
 69→}
