 71→export function buildSheetScene(project, sheet) {
 72→  if (!sheet) return null;
 73→
 74→  const paper = getPaperPreset(sheet.paperSize);
 75→  const titleBlock = buildTitleBlock(project, sheet, paper);
 76→  const contentArea = {
 77→    x: SHEET_MARGIN,
 78→    y: SHEET_MARGIN,
 79→    width: paper.width - SHEET_MARGIN * 2,
 80→    height: paper.height - SHEET_MARGIN * 2,
 81→  };
 82→
 83→  const viewports = (sheet.viewports || []).map((viewport) => (
 84→    buildViewportFrame(viewport, resolveSheetViewportSource(project, viewport))
 85→  ));
 86→
 87→  return {
 88→    paper,
 89→    title: getSheetDisplayLabel(sheet),
 90→    border: {
 91→      x: SHEET_MARGIN,
 92→      y: SHEET_MARGIN,
 93→      width: paper.width - SHEET_MARGIN * 2,
 94→      height: paper.height - SHEET_MARGIN * 2,
 95→    },
 96→    contentArea,
 97→    titleBlock,
 98→    viewports,
 99→  };
100→}

