136→  // Ctrl+S save
137→  useEffect(() => {
138→    const handler = (e) => {
139→      if (isTypingTarget(e.target)) return;
140→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
141→        e.preventDefault();
142→        handleSave();
143→      }
144→    };
145→    window.addEventListener('keydown', handler);
146→    return () => window.removeEventListener('keydown', handler);
147→  }, [handleSave]);
148→
149→  const handleLoadClick = useCallback(async () => {
150→    setSavedProjects(await listProjects());
151→    setShowLoadModal(true);
152→  }, []);
153→
154→  const handleLoad = useCallback(async (id) => {
155→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
156→    try {
157→      const { project: loaded, savedAt } = await loadProject(id);
158→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
159→      setShowLoadModal(false);
160→    } catch (err) {
161→      alert('Failed to load project: ' + err.message);
162→    }
163→  }, [isDirty, dispatch]);
164→
165→  const handleDelete = useCallback(async (id, name) => {
166→    const confirmed = window.confirm(`Delete "${name}"? This cannot be undone.`);
167→    if (!confirmed) return;
168→
169→    try {
170→      await deleteProject(id);
171→      setSavedProjects(projects => projects.filter(project => project.id !== id));
172→    } catch (err) {
173→      alert('Failed to delete project: ' + err.message);
174→    }
175→  }, []);
176→
177→  return (
178→    <EditorProvider
179→      initialActiveFloorId={initialActiveFloorId}
180→      availableFloorIds={availableFloorIds}
181→    >
182→      <EditorShell
183→        project={project}
184→        handleNew={handleNew}
185→        handleSave={handleSave}
186→        handleLoadClick={handleLoadClick}
187→        isSidebarCollapsed={isSidebarCollapsed}
188→        isPropertiesCollapsed={isPropertiesCollapsed}
189→        onToggleSidebar={() => setIsSidebarCollapsed(value => !value)}
190→        onToggleProperties={() => setIsPropertiesCollapsed(value => !value)}
191→      />
192→
193→      {showLoadModal && (
194→        <Modal title="Load Project" onClose={() => setShowLoadModal(false)}>
195→          {savedProjects.length === 0 ? (
196→            <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px' }}>
197→              No saved projects found.
198→            </p>
199→          ) : (
200→            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
201→              {savedProjects.map(p => (
202→                <div
203→                  key={p.id}
204→                  style={{
205→                    display: 'flex',
206→                    justifyContent: 'space-between',
207→                    alignItems: 'center',
208→                    padding: '10px 12px',
209→                    border: '1px solid var(--color-border)',
210→                    borderRadius: 'var(--radius-md)',
211→                    background: 'var(--color-surface-elevated)',
212→                    fontSize: '13px',
213→                  }}
214→                >
215→                  <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
216→                    <span style={{ fontWeight: 500 }}>{p.name}</span>
217→                    <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
218→                      {new Date(p.savedAt).toLocaleDateString()}
219→                    </span>
220→                  </div>
221→                  <div style={{ display: 'flex', gap: '8px' }}>
222→                    <button
223→                      onClick={() => handleLoad(p.id)}
224→                      style={{
225→                        padding: '6px 12px',
226→                        border: '1px solid var(--color-border)',
227→                        borderRadius: 'var(--radius-sm)',
228→                        cursor: 'pointer',
229→                        background: 'var(--color-surface-elevated)',
230→                        fontSize: '12px',
231→                        fontWeight: 500,
232→                      }}
233→                    >
234→                      Load
235→                    </button>
236→                    <button
237→                      onClick={() => handleDelete(p.id, p.name)}
238→                      style={{
239→                        padding: '6px 12px',
240→                        border: '1px solid var(--color-danger-subtle)',
241→                        borderRadius: 'var(--radius-sm)',
242→                        cursor: 'pointer',
243→                        background: 'var(--color-danger-subtle)',
244→                        color: 'var(--color-danger)',
245→                        fontSize: '12px',
246→                      }}
247→                    >
248→                      Delete
249→                    </button>
250→                  </div>
251→                </div>
252→              ))}
253→            </div>
254→          )}
255→          <button
256→            onClick={() => setShowLoadModal(false)}
257→            style={{
258→              marginTop: '16px',
259→              padding: '8px 16px',
260→              border: '1px solid var(--color-border)',
261→              borderRadius: 'var(--radius-sm)',
262→              cursor: 'pointer',
263→              fontSize: '13px',
264→              fontWeight: 500,
265→              background: 'var(--color-surface-elevated)',
266→            }}
267→          >
268→            Cancel
269→          </button>
270→        </Modal>
271→      )}
272→    </EditorProvider>
273→  );
274→}
275→
276→export default function App() {
277→  return (
278→    <ProjectProvider>
279→      <ClipboardProvider>
280→        <AppInner />
281→      </ClipboardProvider>
282→    </ProjectProvider>
283→  );
284→}
