148→function parseTransform(transform = '') {
149→  let matrix = new DOMMatrix();
150→  const pattern = /([a-zA-Z]+)\(([^)]*)\)/g;
151→  let match = pattern.exec(transform);
152→  while (match) {
153→    const [, name, argsString] = match;
154→    const args = parseNumberList(argsString);
155→    switch (name) {
156→      case 'translate':
157→        matrix = matrix.multiply(new DOMMatrix().translate(args[0] || 0, args[1] || 0));
158→        break;
159→      case 'scale':
160→        matrix = matrix.multiply(new DOMMatrix().scale(args[0] ?? 1, args[1] ?? args[0] ?? 1));
161→        break;
162→      case 'rotate':
163→        if (args.length >= 3) {
164→          matrix = matrix.multiply(new DOMMatrix().translate(args[1], args[2]).rotate(args[0]).translate(-args[1], -args[2]));
165→        } else {
166→          matrix = matrix.multiply(new DOMMatrix().rotate(args[0] || 0));
167→        }
168→        break;
169→      case 'matrix':
170→        if (args.length >= 6) {
171→          matrix = matrix.multiply(new DOMMatrix([args[0], args[1], args[2], args[3], args[4], args[5]]));
172→        }
173→        break;
174→      default:
175→        break;
176→    }
177→    match = pattern.exec(transform);
178→  }
179→  return matrix;
180→}
