199→      width: Number(svgElement.getAttribute('width')) || 0,
200→      height: Number(svgElement.getAttribute('height')) || 0,
201→    };
202→  }
203→  return {
204→    minX: values[0],
205→    minY: values[1],
206→    width: values[2],
207→    height: values[3],
208→  };
