215→  if (element.tagName.toLowerCase() === 'svg') {
216→    const x = Number(element.getAttribute('x')) || 0;
217→    const y = Number(element.getAttribute('y')) || 0;
218→    const width = Number(element.getAttribute('width')) || 0;
219→    const height = Number(element.getAttribute('height')) || 0;
220→    const viewBox = parseViewBox(element);
221→    const scaleX = viewBox.width ? width / viewBox.width : 1;
222→    const scaleY = viewBox.height ? height / viewBox.height : 1;
223→    matrix = matrix
224→      .translate(x, y)
225→      .scale(scaleX || 1, scaleY || 1)
226→      .translate(-viewBox.minX, -viewBox.minY);
227→  }
228→
229→  if (transformAttr) {
230→    matrix = matrix.multiply(parseTransform(transformAttr));
231→  }
232→
233→  return matrix;
