266→  const opacity = Number.parseFloat(style.opacity || '1') || 1;
267→  const fillOpacity = fill ? opacity * (Number.parseFloat(style.fillOpacity || '1') || 1) : 0;
268→  const strokeOpacity = stroke ? opacity * (Number.parseFloat(style.strokeOpacity || '1') || 1) : 0;
269→
270→  return {
271→    fill,
272→    stroke,
273→    strokeWidth,
274→    lineCap,
275→    lineJoin,
276→    dashArray,
277→    fontSize,
278→    fontFamily: style.fontFamily || 'Arial',
279→    fontWeight: style.fontWeight || '400',
280→    textAnchor: style.textAnchor || 'start',
281→    dominantBaseline: style.dominantBaseline || 'auto',
282→    fillOpacity,
283→    strokeOpacity,
