306→function buildArcPoints(start, rx, ry, rotation, largeArcFlag, sweepFlag, end) {
307→  if (!start || !end) return [end];
308→  if (Math.abs(rotation) > 1e-6 || Math.abs(rx - ry) > 1e-6) return [end];
309→  const radius = Math.abs(rx);
310→  const dx = end.x - start.x;
311→  const dy = end.y - start.y;
312→  const chordLength = Math.hypot(dx, dy);
313→  if (chordLength < 1e-6 || radius < chordLength / 2) return [end];
314→
315→  const midX = (start.x + end.x) / 2;
316→  const midY = (start.y + end.y) / 2;
317→  const halfChord = chordLength / 2;
318→  const offsetLength = Math.sqrt(Math.max(0, radius * radius - halfChord * halfChord));
319→  const ux = -dy / chordLength;
320→  const uy = dx / chordLength;
321→
322→  const centers = [
323→    { x: midX + ux * offsetLength, y: midY + uy * offsetLength },
324→    { x: midX - ux * offsetLength, y: midY - uy * offsetLength },
325→  ];
326→
327→  for (const center of centers) {
328→    const startAngle = Math.atan2(start.y - center.y, start.x - center.x);
329→    const endAngle = Math.atan2(end.y - center.y, end.x - center.x);
330→    const sweepDelta = normalizeSweep(endAngle - startAngle, Boolean(sweepFlag));
331→    const isLarge = Math.abs(sweepDelta) > Math.PI;
332→    if (isLarge !== Boolean(largeArcFlag)) continue;
333→
334→    const points = [];
335→    for (let index = 1; index <= ARC_SEGMENTS; index += 1) {
336→      const angle = startAngle + (sweepDelta * index) / ARC_SEGMENTS;
337→      points.push({
338→        x: center.x + radius * Math.cos(angle),
339→        y: center.y + radius * Math.sin(angle),
340→      });
341→    }
342→    return points;
343→  }
344→
345→  return [end];
346→}
