105→  const availableFloorIds = useMemo(() => orderedFloors.map((floor) => floor.id), [orderedFloors]);
106→  const initialActiveFloorId = getDefaultActiveFloorId(project);
107→  const [showLoadModal, setShowLoadModal] = useState(false);
