112→  useAutosave(project, isDirty, dispatch);
113→
114→  // beforeunload warning
115→  useEffect(() => {
116→    const handler = (e) => {
117→      if (isDirty) {
118→        e.preventDefault();
119→        e.returnValue = '';
120→      }
121→    };
122→    window.addEventListener('beforeunload', handler);
123→    return () => window.removeEventListener('beforeunload', handler);
124→  }, [isDirty]);
