454→class PdfBuilder {
455→  constructor(pageWidthPt, pageHeightPt) {
456→    this.pageWidthPt = pageWidthPt;
457→    this.pageHeightPt = pageHeightPt;
458→    this.content = [];
459→    this.alphaMap = new Map();
460→  }
461→
462→  write(line) {
463→    this.content.push(`${line}\n`);
464→  }
465→
466→  alphaName(fillOpacity, strokeOpacity) {
467→    const fill = Math.max(0, Math.min(1, fillOpacity));
468→    const stroke = Math.max(0, Math.min(1, strokeOpacity));
469→    if (fill >= 0.999 && stroke >= 0.999) return null;
470→    const key = `${fill.toFixed(3)}:${stroke.toFixed(3)}`;
471→    if (!this.alphaMap.has(key)) {
472→      this.alphaMap.set(key, {
473→        name: `GS${this.alphaMap.size + 1}`,
474→        fill,
475→        stroke,
476→      });
477→    }
478→    return this.alphaMap.get(key).name;
479→  }
480→
481→  applyStyle(style, { fillAllowed = true, strokeAllowed = true } = {}) {
482→    if (strokeAllowed && style.stroke && style.strokeWidth > 0) {
483→      this.write(`${fmt(style.stroke[0])} ${fmt(style.stroke[1])} ${fmt(style.stroke[2])} RG`);
484→      this.write(`${fmt(style.strokeWidth)} w`);
485→      this.write(`${lineCapCode(style.lineCap)} J`);
486→      this.write(`${lineJoinCode(style.lineJoin)} j`);
487→      if (style.dashArray.length) {
488→        this.write(`[${style.dashArray.map(fmt).join(' ')}] 0 d`);
489→      } else {
490→        this.write('[] 0 d');
491→      }
492→    }
493→
494→    if (fillAllowed && style.fill) {
495→      this.write(`${fmt(style.fill[0])} ${fmt(style.fill[1])} ${fmt(style.fill[2])} rg`);
496→    }
497→
498→    const alphaName = this.alphaName(
499→      fillAllowed ? style.fillOpacity : 1,
500→      strokeAllowed ? style.strokeOpacity : 1
501→    );
502→    if (alphaName) {
503→      this.write(`/${alphaName} gs`);
504→    }
505→  }
506→
507→  finish() {
508→    const encoder = new TextEncoder();
509→    const contentStream = encoder.encode(this.content.join(''));
510→    const alphaObjects = [...this.alphaMap.values()];
511→    const fontObjectNumber = 4;
512→    const firstAlphaObjectNumber = 5;
513→    const contentObjectNumber = firstAlphaObjectNumber + alphaObjects.length;
514→    const totalObjects = contentObjectNumber;
515→    const objects = [];
516→
517→    objects[1] = encoder.encode('1 0 obj\n<< /Type /Catalog /Pages 2 0 R >>\nendobj\n');
518→    objects[2] = encoder.encode('2 0 obj\n<< /Type /Pages /Kids [3 0 R] /Count 1 >>\nendobj\n');
519→
520→    const extGStateEntries = alphaObjects
521→      .map((entry, index) => `/${entry.name} ${firstAlphaObjectNumber + index} 0 R`)
522→      .join(' ');
523→
524→    objects[3] = encoder.encode(
525→      `3 0 obj\n<< /Type /Page /Parent 2 0 R /MediaBox [0 0 ${fmt(this.pageWidthPt)} ${fmt(this.pageHeightPt)}] /Resources << /Font << /F1 ${fontObjectNumber} 0 R >>${extGStateEntries ? ` /ExtGState << ${extGStateEntries} >>` : ''} >> /Contents ${contentObjectNumber} 0 R >>\nendobj\n`
526→    );
527→    objects[4] = encoder.encode('4 0 obj\n<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>\nendobj\n');
528→
529→    alphaObjects.forEach((entry, index) => {
530→      objects[firstAlphaObjectNumber + index] = encoder.encode(
531→        `${firstAlphaObjectNumber + index} 0 obj\n<< /Type /ExtGState /ca ${fmt(entry.fill)} /CA ${fmt(entry.stroke)} >>\nendobj\n`
532→      );
533→    });
534→
535→    const contentHeader = encoder.encode(
536→      `${contentObjectNumber} 0 obj\n<< /Length ${contentStream.length} >>\nstream\n`
537→    );
538→    const contentFooter = encoder.encode('endstream\nendobj\n');
539→    objects[contentObjectNumber] = new Uint8Array(contentHeader.length + contentStream.length + contentFooter.length);
540→    objects[contentObjectNumber].set(contentHeader, 0);
541→    objects[contentObjectNumber].set(contentStream, contentHeader.length);
542→    objects[contentObjectNumber].set(contentFooter, contentHeader.length + contentStream.length);
543→
544→    const header = encoder.encode('%PDF-1.4\n');
545→    const binaryComment = new Uint8Array([0x25, 0xe2, 0xe3, 0xcf, 0xd3, 0x0a]);
546→    const offsets = [0];
547→    let offset = header.length + binaryComment.length;
548→
549→    for (let index = 1; index <= totalObjects; index += 1) {
550→      offsets[index] = offset;
551→      offset += objects[index].length;
552→    }
553→
554→    const xrefStart = offset;
555→    let xref = `xref\n0 ${totalObjects + 1}\n0000000000 65535 f \n`;
556→    for (let index = 1; index <= totalObjects; index += 1) {
557→      xref += `${String(offsets[index]).padStart(10, '0')} 00000 n \n`;
558→    }
559→    const trailer = `trailer\n<< /Size ${totalObjects + 1} /Root 1 0 R >>\nstartxref\n${xrefStart}\n%%EOF`;
560→
561→    return new Blob(
562→      [header, binaryComment, ...objects.slice(1), encoder.encode(xref), encoder.encode(trailer)],
563→      { type: 'application/pdf' }
564→    );
565→  }
566→}
