787→function renderRect(builder, element) {
788→  const x = Number(element.getAttribute('x')) || 0;
789→  const y = Number(element.getAttribute('y')) || 0;
790→  const width = Number(element.getAttribute('width')) || 0;
791→  const height = Number(element.getAttribute('height')) || 0;
792→  const style = computeStyle(element);
793→
794→  builder.write('q');
795→  builder.applyStyle(style);
796→  builder.write(`${fmt(x)} ${fmt(y)} ${fmt(width)} ${fmt(height)} re`);
797→  if (style.fill && style.stroke && style.strokeWidth > 0) builder.write('B');
798→  else if (style.fill) builder.write('f');
799→  else if (style.stroke && style.strokeWidth > 0) builder.write('S');
800→  builder.write('Q');
801→}
