838→function estimateTextWidth(text, fontSize) {
839→  return text.length * fontSize * 0.56;
840→}
841→
842→function renderTextLine(builder, text, x, y, style) {
843→  if (!text) return;
844→  let drawX = x;
845→  const textWidth = estimateTextWidth(text, style.fontSize);
846→  if (style.textAnchor === 'middle') drawX -= textWidth / 2;
847→  else if (style.textAnchor === 'end') drawX -= textWidth;
848→
849→  let baselineY = y;
850→  if (style.dominantBaseline === 'middle') {
851→    baselineY += style.fontSize * 0.32;
852→  }
853→
854→  builder.write('q');
855→  builder.applyStyle(style, { fillAllowed: true, strokeAllowed: false });
856→  builder.write('BT');
857→  builder.write(`/F1 ${fmt(style.fontSize)} Tf`);
858→  builder.write(`1 0 0 -1 ${fmt(drawX)} ${fmt(baselineY)} Tm`);
859→  builder.write(`(${escapePdfText(text)}) Tj`);
860→  builder.write('ET');
861→  builder.write('Q');
862→}
863→
864→function getTextLines(element) {
865→  const x = Number(element.getAttribute('x')) || 0;
866→  const y = Number(element.getAttribute('y')) || 0;
867→  const tspans = [...element.children].filter((child) => child.tagName?.toLowerCase() === 'tspan');
868→
869→  if (!tspans.length) {
870→    return [{ text: element.textContent || '', x, y }];
871→  }
872→
873→  let currentY = y;
874→  return tspans.map((tspan, index) => {
875→    const text = tspan.textContent || '';
876→    const lineX = tspan.hasAttribute('x') ? Number(tspan.getAttribute('x')) : x;
877→    if (tspan.hasAttribute('y')) {
878→      currentY = Number(tspan.getAttribute('y'));
879→    } else if (tspan.hasAttribute('dy')) {
880→      currentY += Number(tspan.getAttribute('dy'));
881→    } else if (index > 0) {
882→      currentY = y;
883→    }
884→    return { text, x: lineX, y: currentY };
885→  });
886→}
887→
888→function renderText(builder, element) {
889→  const style = computeStyle(element);
890→  if (!style.fill) return;
891→  const lines = getTextLines(element);
892→  lines.forEach((line) => renderTextLine(builder, line.text, line.x, line.y, style));
893→}
